# DDx GraphQL Schema
# Single source of truth for the SvelteKit UI.
# Every type field is doc-commented. Relay cursor connections on all lists.

# ============================================
# Scalars
# ============================================

"""ISO-8601 datetime string"""
scalar DateTime

"""Arbitrary JSON blob (used for opaque map fields)"""
scalar JSON

# ============================================
# Interfaces
# ============================================

"""Node is the Relay global object identification interface"""
interface Node {
  """Globally unique identifier"""
  id: ID!
}

# ============================================
# Pagination (Relay Cursor Connections)
# ============================================

"""PageInfo carries cursor-based pagination state (Relay spec)"""
type PageInfo {
  """True when more edges exist after the last returned edge"""
  hasNextPage: Boolean!
  """True when more edges exist before the first returned edge"""
  hasPreviousPage: Boolean!
  """Cursor of the first edge in the current page (null when empty)"""
  startCursor: String
  """Cursor of the last edge in the current page (null when empty)"""
  endCursor: String
}

# ============================================
# Node & Project
# ============================================

"""NodeInfo represents the running ddx-server instance"""
type NodeInfo implements Node {
  """Unique node identifier (stable across restarts)"""
  id: ID!
  """Human-readable node name"""
  name: String!
  """Timestamp when the server process started"""
  startedAt: DateTime!
  """Timestamp of the most recent heartbeat"""
  lastSeen: DateTime!
}

"""Project represents a registered ddx project on this node"""
type Project implements Node {
  """Unique project identifier"""
  id: ID!
  """Short display name"""
  name: String!
  """Absolute filesystem path to the project root"""
  path: String!
  """Git remote URL, if configured"""
  gitRemote: String
  """When the project was first registered with the server"""
  registeredAt: DateTime!
  """Timestamp of the last successful probe"""
  lastSeen: DateTime!
  """True when the project path is inaccessible"""
  unreachable: Boolean
  """Set when the project has been tombstoned (soft-deleted)"""
  tombstonedAt: DateTime
}

"""ProjectEdge is one edge in a ProjectConnection"""
type ProjectEdge {
  """The project at this position"""
  node: Project!
  """Opaque cursor for pagination"""
  cursor: String!
}

"""ProjectConnection is a Relay cursor connection of projects"""
type ProjectConnection {
  """Ordered list of project edges"""
  edges: [ProjectEdge!]!
  """Pagination metadata"""
  pageInfo: PageInfo!
  """Total number of projects matching the filter"""
  totalCount: Int!
}

# ============================================
# Beads
# ============================================

"""Bead is a portable work item with lifecycle metadata"""
type Bead implements Node {
  """Unique bead identifier (e.g. "ddx-a1b2c3d4")"""
  id: ID!
  """Short summary of the work"""
  title: String!
  """Lifecycle status: open, in-progress, closed, blocked"""
  status: String!
  """Numeric priority (lower is higher priority)"""
  priority: Int!
  """Issue classification (e.g. "task", "bug", "spike")"""
  issueType: String!
  """Agent or human currently responsible"""
  owner: String
  """When the bead was created"""
  createdAt: DateTime!
  """Who or what created the bead"""
  createdBy: String
  """Last modification timestamp"""
  updatedAt: DateTime!
  """Freeform labels for filtering and grouping"""
  labels: [String!]
  """Project identifier this bead belongs to"""
  projectID: String
  """Parent bead ID for hierarchy"""
  parent: String
  """Full description / body text"""
  description: String
  """Acceptance criteria text"""
  acceptance: String
  """Freeform notes appended during work"""
  notes: String
  """Dependency edges to other beads"""
  dependencies: [Dependency!]
}

"""Dependency is a directed edge between two beads"""
type Dependency {
  """The bead that has the dependency"""
  issueId: String!
  """The bead that must be completed first"""
  dependsOnId: String!
  """Dependency kind (e.g. "blocks", "relates-to")"""
  type: String!
  """When the dependency was created"""
  createdAt: String
  """Who created the dependency"""
  createdBy: String
  """Opaque metadata attached to the link"""
  metadata: String
}

"""BeadEdge is one edge in a BeadConnection"""
type BeadEdge {
  """The bead at this position"""
  node: Bead!
  """Opaque cursor for pagination"""
  cursor: String!
}

"""BeadConnection is a Relay cursor connection of beads"""
type BeadConnection {
  """Ordered list of bead edges"""
  edges: [BeadEdge!]!
  """Pagination metadata"""
  pageInfo: PageInfo!
  """Total number of beads matching the filter"""
  totalCount: Int!
}

"""BeadStatusCounts holds aggregate bead counts by status"""
type BeadStatusCounts {
  """Number of beads in open status"""
  open: Int!
  """Number of beads in closed status"""
  closed: Int!
  """Number of beads with unclosed dependencies"""
  blocked: Int!
  """Number of open beads whose dependencies are all closed"""
  ready: Int!
  """Total number of beads"""
  total: Int!
import type { PageLoad } from './$types';
import { createClient } from '$lib/gql/client';
import { gql } from 'graphql-request';

const EFFICACY_ROWS_QUERY = gql`
	query EfficacyRows($projectId: String) {
		efficacyRows(projectId: $projectId) {
			rowKey
			harness
			provider
			model
			attempts
			successes
			successRate
			medianInputTokens
			medianOutputTokens
			medianDurationMs
			medianCostUsd
			warning {
				kind
				threshold
			}
		}
	}
`;

const COMPARISONS_QUERY = gql`
	query Comparisons {
		comparisons {
			id
			state
			armCount
		}
	}
`;

interface EfficacyWarning {
	kind: string;
	threshold: number | null;
}

export interface EfficacyRow {
	rowKey?: string;
	harness: string;
	provider: string;
	model: string;
	attempts: number;
	successes: number;
	successRate: number;
	medianInputTokens: number;
	medianOutputTokens: number;
	medianDurationMs: number;
	medianCostUsd: number | null;
	warning: EfficacyWarning | null;
	tier?: string | null;
	labels?: string[] | null;
	specId?: string | null;
}

export interface ComparisonRecord {
	id: string;
	state: string;
	armCount: number;
}

interface EfficacyRowsResult {
	efficacyRows: EfficacyRow[];
}

interface ComparisonsResult {
	comparisons: ComparisonRecord[];
}

export const load: PageLoad = async ({ params, url, fetch }) => {
	const client = createClient(fetch as unknown as typeof globalThis.fetch);
	const [rowsData, comparisonsData] = await Promise.all([
		client.request<EfficacyRowsResult>(EFFICACY_ROWS_QUERY, { projectId: params.projectId }),
		client.request<ComparisonsResult>(COMPARISONS_QUERY)
	]);

	return {
		projectId: params.projectId,
		rows: rowsData.efficacyRows,
		comparisons: comparisonsData.comparisons,
		activeTier: url.searchParams.get('tier') ?? '',
		activeLabel: url.searchParams.get('label') ?? '',
		activeSpecId: url.searchParams.get('spec-id') ?? ''
	};
};

	return out
}

type efficacySnapshot struct {
	rows     []*EfficacyRow
	attempts map[string][]*EfficacyAttempt
}

type sessionEfficacyCacheEntry struct {
	fingerprint string
	snapshot    efficacySnapshot
}

var sessionEfficacyCache struct {
	sync.Mutex
	byQuery map[string]sessionEfficacyCacheEntry
}

func (r *queryResolver) efficacySnapshot(since, until, projectID *string) (efficacySnapshot, error) {
	projectRoot := r.WorkingDir
	if projectID != nil && strings.TrimSpace(*projectID) != "" {
		projectRoot = r.projectRoot(strings.TrimSpace(*projectID))
	}
	startedAfter, err := parseOptionalEfficacyTime("since", since)
	if err != nil {
		return efficacySnapshot{}, err
	}
	startedBefore, err := parseOptionalEfficacyTime("until", until)
	if err != nil {
		return efficacySnapshot{}, err
	}
	logDir := agent.SessionLogDirForWorkDir(projectRoot)
	query := agent.SessionIndexQuery{
		StartedAfter:  startedAfter,
		StartedBefore: startedBefore,
	}
	cacheKey := sessionEfficacyCacheKey(logDir, startedAfter, startedBefore)
	fingerprint, err := sessionEfficacyIndexFingerprint(logDir, query)
	if err != nil {
		return efficacySnapshot{}, err
	}
	sessionEfficacyCache.Lock()
	if sessionEfficacyCache.byQuery == nil {
		sessionEfficacyCache.byQuery = map[string]sessionEfficacyCacheEntry{}
	}
	if cached, ok := sessionEfficacyCache.byQuery[cacheKey]; ok && cached.fingerprint == fingerprint {
		sessionEfficacyCache.Unlock()
		return cached.snapshot, nil
	}
	sessionEfficacyCache.Unlock()

	entries, err := agent.ReadSessionIndex(logDir, query)
	if err != nil {
		return efficacySnapshot{}, err
	}
	snap := buildEfficacySnapshotFromSessionEntries(entries)
	sessionEfficacyCache.Lock()
	sessionEfficacyCache.byQuery[cacheKey] = sessionEfficacyCacheEntry{fingerprint: fingerprint, snapshot: snap}
	sessionEfficacyCache.Unlock()
	return snap, nil
}

func sessionEfficacyCacheKey(logDir string, startedAfter, startedBefore *time.Time) string {
	return strings.Join([]string{logDir, timeKey(startedAfter), timeKey(startedBefore)}, "|")
}

func timeKey(t *time.Time) string {
	if t == nil {
		return ""
	}
	return t.UTC().Format(time.RFC3339Nano)
}

func sessionEfficacyIndexFingerprint(logDir string, query agent.SessionIndexQuery) (string, error) {
	files, err := agent.SessionIndexShardFiles(logDir, query)
	if err != nil {
		return "", err
	}
	parts := make([]string, 0, len(files))
	for _, file := range files {
		info, err := os.Stat(file)
		if os.IsNotExist(err) {
			continue
		}
		if err != nil {
			return "", err
		}
		parts = append(parts, fmt.Sprintf("%s:%d:%d", file, info.Size(), info.ModTime().UnixNano()))
	}
	return strings.Join(parts, "|"), nil
}

func parseOptionalEfficacyTime(name string, raw *string) (*time.Time, error) {
	if raw == nil || strings.TrimSpace(*raw) == "" {
		return nil, nil
	}
	value := strings.TrimSpace(*raw)
	for _, layout := range []string{time.RFC3339Nano, time.RFC3339, "2006-01-02"} {
		if parsed, err := time.Parse(layout, value); err == nil {
			utc := parsed.UTC()
			return &utc, nil
		}
	}
	return nil, fmt.Errorf("%s must be RFC3339 or YYYY-MM-DD, got %q", name, value)
}

type sessionEfficacyAttempt struct {
	RowKey       string
	BeadID       string
	Outcome      string
	Harness      string
	Provider     string
	Model        string
	InputTokens  int
	OutputTokens int
	DurationMs   int
	CostUsd      *float64
	EvidencePath string
	CreatedAt    time.Time
}

func buildEfficacySnapshotFromSessionEntries(entries []agent.SessionIndexEntry) efficacySnapshot {
	grouped := map[string][]sessionEfficacyAttempt{}
	for _, entry := range entries {
		attempt := efficacyAttemptFromSession(entry)
		if attempt.RowKey == "" {
			continue
		}
		grouped[attempt.RowKey] = append(grouped[attempt.RowKey], attempt)
	}
	rows := make([]*EfficacyRow, 0, len(grouped))
	attemptDetails := map[string][]*EfficacyAttempt{}
	for rowKey, group := range grouped {
		sort.Slice(group, func(i, j int) bool { return group[i].CreatedAt.After(group[j].CreatedAt) })
		attemptDetails[rowKey] = make([]*EfficacyAttempt, 0, len(group))
		var inputTokens, outputTokens, durations []int
		var costs []float64
		var successes int
		for _, attempt := range group {
			if attempt.Outcome == "succeeded" {
				successes++
			}
			inputTokens = append(inputTokens, attempt.InputTokens)
			outputTokens = append(outputTokens, attempt.OutputTokens)
			durations = append(durations, attempt.DurationMs)
			if attempt.CostUsd != nil {
				costs = append(costs, *attempt.CostUsd)
			}
			attemptDetails[rowKey] = append(attemptDetails[rowKey], &EfficacyAttempt{
				BeadID:            attempt.BeadID,
				Outcome:           attempt.Outcome,
				DurationMs:        attempt.DurationMs,
				CostUsd:           attempt.CostUsd,
				EvidenceBundleURL: attempt.EvidencePath,
			})
		}
		parts := strings.Split(rowKey, "|")
		row := &EfficacyRow{
			RowKey:             rowKey,
			Harness:            parts[0],
			Provider:           parts[1],
			Model:              parts[2],
			Attempts:           len(group),
			Successes:          successes,
			SuccessRate:        float64(successes) / float64(len(group)),
			MedianInputTokens:  medianInt(inputTokens),
			MedianOutputTokens: medianInt(outputTokens),
			MedianDurationMs:   medianInt(durations),
			MedianCostUsd:      medianFloatPtr(costs),
		}
		if row.SuccessRate < efficacyWarningFloor {
			row.Warning = &EfficacyWarning{Kind: "below-adaptive-floor", Threshold: floatPtr(efficacyWarningFloor)}
		}
		rows = append(rows, row)
	}
	sort.Slice(rows, func(i, j int) bool {
		if rows[i].SuccessRate != rows[j].SuccessRate {
			return rows[i].SuccessRate > rows[j].SuccessRate
		}
		return rows[i].RowKey < rows[j].RowKey
	})

	return efficacySnapshot{rows: rows, attempts: attemptDetails}
}

func efficacyAttemptFromSession(entry agent.SessionIndexEntry) sessionEfficacyAttempt {
	model := firstNonEmpty(entry.Model, "unknown")
	provider := firstNonEmpty(entry.Provider, providerFromModel(model), entry.Harness, "unknown")
	harness := firstNonEmpty(entry.Harness, provider, "unknown")
	cost := efficacyCost(entry)
	outcome := efficacyOutcome(entry)
	return sessionEfficacyAttempt{
		RowKey:       strings.Join([]string{harness, provider, model}, "|"),
		BeadID:       entry.BeadID,
		Outcome:      outcome,
		Harness:      harness,
