	}
	raw := rec.Body.Bytes()
	var payload struct {
		Errors []any `json:"errors"`
	}
	if err := json.Unmarshal(raw, &payload); err != nil {
		t.Fatal(err)
	}
	if len(payload.Errors) > 0 {
		t.Fatalf("graphql errors: %s", raw)
	}
	return raw
}

