	if id == "" {
		id = genSessionID()
	}
	if bundlePath == "" && corr != nil && corr["attempt_id"] != "" {
		bundlePath = filepath.Join(ExecuteBeadArtifactDir, corr["attempt_id"])
	}
	if nativeLogRef == "" && result.AgentSessionID != "" {
