	if nativeSessionID == "" {
		nativeSessionID = result.AgentSessionID
	}
	harness := result.Harness
	if harness == "" {
		harness = opts.Harness
	}
	model := result.Model
	if model == "" {
		model = opts.Model
	}
	outcome := "success"
	if result.ExitCode != 0 || result.Error != "" {
		outcome = "failure"
	}
	return SessionIndexEntry{
